@page "/wheeltest"
@using SkiaSharp
@using SkiaSharp.Views.Blazor

<h3>Wheel Event Test</h3>
<p>Wheel events received: <strong id="wheel-count">@wheelCount</strong></p>
<p>Last wheel delta: <strong id="wheel-delta">@lastDelta</strong></p>

<SKCanvasView OnPaintSurface="OnPaintSurface" style="width:400px;height:300px;border:2px solid black;" />

@code {
    private int wheelCount = 0;
    private int lastDelta = 0;

    private void OnPaintSurface(SKPaintSurfaceEventArgs e)
    {
        var canvas = e.Surface.Canvas;
        canvas.Clear(new SKColor(0x33, 0x66, 0xFF));
        Console.WriteLine($"SUCCESS: Canvas rendered {e.Info.Width}x{e.Info.Height}");
    }
}
